using System.Text.Json;
using TradingBot.Api;
using TradingBot.Options;

namespace TradingBot.Services;

public sealed record EdgeCompressionItem(string WatchlistId,string TransitionId,string Strategy,string MarketIdOrGroupKey,string Title,decimal RawEdge,decimal AfterCostEdge,decimal AfterSafetyEdge,decimal CostDrag,decimal SafetyDrag,decimal TotalDrag,decimal DistanceToBreakEven,decimal DistanceToAlertThreshold,decimal DistanceToNearBreakEvenThreshold,bool RawWouldBePositive,bool AfterCostWouldBePositive,bool AfterSafetyWouldBePositive,bool BlockedByCostOnly,bool BlockedBySafetyOnly,bool BlockedByMarketSpread,string DominantDragComponent,decimal? CompressionStartedEdge,decimal CompressionCurrentEdge,decimal? CompressionDelta,decimal? CompressionRatePerObservation,decimal? BestCompressionDelta,string CompressionDirection,int ObservationsInCompressionWindow,bool CrossedNearBreakEvenDuringWindow,bool CrossedAlertDuringWindow,bool CrossedPositiveDuringWindow,string TransitionState,string RecommendedAction);
public sealed record EdgeCompressionSnapshot(bool Enabled,int Items,int NearBreakEven,int Compressing,int Expanding,int Flat,int RawPositive,int AfterCostPositive,int AfterSafetyPositive,int BlockedByMarketSpread,int BlockedByCost,int BlockedBySafety,string BestStrategy,decimal? BestRawEdge,decimal? BestAfterCostEdge,decimal? BestAfterSafetyEdge,decimal? BestDistanceToBreakEven,decimal? MedianDistanceToBreakEven,decimal? P95AfterSafetyEdge,string DominantDragComponent,bool Consistent,IReadOnlyList<EdgeCompressionItem> RankedItems);

public sealed class EdgeCompressionService
{
    private readonly TradingBotOptions _options; private readonly object _gate=new(); private readonly Dictionary<string,List<decimal>> _history=new(StringComparer.OrdinalIgnoreCase); private readonly Dictionary<string,decimal> _bestDelta=new(StringComparer.OrdinalIgnoreCase);
    public EdgeCompressionService(TradingBotOptions options)=>_options=options;
    public EdgeCompressionSnapshot Update(FocusUniverseSnapshot? focus, EdgeTransitionSnapshot? transition, RuntimeHealthSnapshot health, string root)
    { lock(_gate){ var o=_options.EdgeCompression; var enabled=o.Enabled && (!o.RequireFocusUniverse || focus?.Enabled==true) && (!o.RequireEdgeTransition || transition?.Enabled==true); if(!enabled){var d=Snapshot(false,Array.Empty<EdgeCompressionItem>(),health); if(o.ExportEnabled) TryExport(d,health,focus,transition,root); return d;} var transitions=(transition?.Items??Array.Empty<EdgeTransitionItem>()).ToDictionary(x=>x.WatchlistId,StringComparer.OrdinalIgnoreCase); var items=new List<EdgeCompressionItem>(); foreach(var f in (focus?.Items??Array.Empty<FocusUniverseItem>()).Take(Math.Max(0,o.MaxItems))){ if(!f.ValidPriced || !f.CurrentRawEdge.HasValue || !f.CurrentAfterCostEdge.HasValue) continue; if(IsInvalid(f.LastRejectedReason)) continue; transitions.TryGetValue(f.WatchlistId,out var t); var raw=f.CurrentRawEdge.Value; var cost=f.CurrentAfterCostEdge.Value; var safety=f.CurrentAfterSafetyEdge; var hist=Record(f.WatchlistId,safety,o.CompressionWindowObservations); var started=hist.Count>0?hist[0]:(decimal?)null; decimal? delta=started.HasValue?safety-started.Value:null; if(delta.HasValue) _bestDelta[f.WatchlistId]=Math.Max(_bestDelta.GetValueOrDefault(f.WatchlistId,delta.Value),delta.Value); var dir=hist.Count<2?"InsufficientData":delta>0.0001m?"CompressingTowardBreakEven":delta<-0.0001m?"ExpandingAwayFromBreakEven":"Flat"; var costDrag=raw-cost; var safetyDrag=cost-safety; var dominant=Dominant(raw,cost,safety,f.LastRejectedReason); var action=Action(dominant,dir,safety,o.NearBreakEvenThreshold); items.Add(new EdgeCompressionItem(f.WatchlistId,t?.TransitionId??string.Empty,f.Strategy,f.MarketIdOrGroupKey,f.Title,raw,cost,safety,costDrag,safetyDrag,raw-safety,0m-safety,_options.EdgeTransition.AlertThreshold-safety,o.NearBreakEvenThreshold-safety,raw>0,cost>0,safety>0,raw>0&&cost<=0,cost>0&&safety<=0,raw<=0,dominant,started,safety,delta,hist.Count>1?delta/(hist.Count-1):null,_bestDelta.GetValueOrDefault(f.WatchlistId),dir,hist.Count,hist.Any(x=>x>=o.NearBreakEvenThreshold),hist.Any(x=>x>=_options.EdgeTransition.AlertThreshold),hist.Any(x=>x>_options.EdgeTransition.PositiveThreshold),t?.TransitionState??"Unknown",action)); } var s=Snapshot(true,items.OrderByDescending(x=>x.AfterSafetyEdge).ToArray(),health); if(!s.Consistent) Console.WriteLine("[EDGE_COMPRESSION_WARNING] Reason=AfterSafetyPositiveExceedsTotalPositive"); if(!_options.Diagnostics.OperationalQuietMode) Console.WriteLine($"[EDGE_COMPRESSION_SUMMARY] Enabled={s.Enabled.ToString().ToLowerInvariant()} Items={s.Items} NearBreakEven={s.NearBreakEven} Compressing={s.Compressing} Expanding={s.Expanding} Flat={s.Flat} RawPositive={s.RawPositive} AfterCostPositive={s.AfterCostPositive} AfterSafetyPositive={s.AfterSafetyPositive} BlockedByMarketSpread={s.BlockedByMarketSpread} BlockedByCost={s.BlockedByCost} BlockedBySafety={s.BlockedBySafety} BestStrategy={s.BestStrategy} BestRawEdge={Fmt(s.BestRawEdge)} BestAfterCostEdge={Fmt(s.BestAfterCostEdge)} BestAfterSafetyEdge={Fmt(s.BestAfterSafetyEdge)} BestDistanceToBreakEven={Fmt(s.BestDistanceToBreakEven)} MedianDistanceToBreakEven={Fmt(s.MedianDistanceToBreakEven)} P95AfterSafetyEdge={Fmt(s.P95AfterSafetyEdge)} DominantDrag={s.DominantDragComponent} Consistent={s.Consistent.ToString().ToLowerInvariant()}"); if(o.ExportEnabled) TryExport(s,health,focus,transition,root); return s; }}
    private List<decimal> Record(string id,decimal edge,int window){ if(!_history.TryGetValue(id,out var h)) _history[id]=h=new(); h.Add(edge); var cap=Math.Max(1,window); if(h.Count>cap) h.RemoveRange(0,h.Count-cap); return h; }
    private EdgeCompressionSnapshot Snapshot(bool enabled,IReadOnlyList<EdgeCompressionItem> a,RuntimeHealthSnapshot h){ var best=a.FirstOrDefault(); var totalPositive=h.StrategyCounters.Values.Sum(x=>x.PositiveEdges); var consistent=a.Count(x=>x.AfterSafetyWouldBePositive)<=totalPositive; var med=Percentile(a.Select(x=>x.DistanceToBreakEven).OrderBy(x=>x).ToArray(),0.5); var p95=Percentile(a.Select(x=>x.AfterSafetyEdge).OrderBy(x=>x).ToArray(),0.95); var dom=a.GroupBy(x=>x.DominantDragComponent).OrderByDescending(x=>x.Count()).ThenBy(x=>x.Key).FirstOrDefault()?.Key??"Unknown"; return new(enabled,a.Count,a.Count(x=>x.AfterSafetyEdge>=_options.EdgeCompression.NearBreakEvenThreshold),a.Count(x=>x.CompressionDirection=="CompressingTowardBreakEven"),a.Count(x=>x.CompressionDirection=="ExpandingAwayFromBreakEven"),a.Count(x=>x.CompressionDirection=="Flat"),a.Count(x=>x.RawWouldBePositive),a.Count(x=>x.AfterCostWouldBePositive),a.Count(x=>x.AfterSafetyWouldBePositive),a.Count(x=>x.BlockedByMarketSpread),a.Count(x=>x.BlockedByCostOnly),a.Count(x=>x.BlockedBySafetyOnly),best?.Strategy??"N/A",best?.RawEdge,best?.AfterCostEdge,best?.AfterSafetyEdge,best?.DistanceToBreakEven,med,p95,dom,consistent,a); }
    private static decimal? Percentile(decimal[] v,double p){ if(v.Length==0)return null; var i=(int)Math.Clamp(Math.Ceiling(p*v.Length)-1,0,v.Length-1); return v[i]; }
    private static string Dominant(decimal raw,decimal cost,decimal safety,string r){ if(IsInvalid(r)) return r.Contains("Missing",StringComparison.OrdinalIgnoreCase)?"MissingPricing":"DataQuality"; if(raw<=0) return "MarketSpread"; return Math.Abs(raw-cost)>=Math.Abs(cost-safety)?"CostModel":"SafetyBuffer"; }
    private static string Action(string d,string dir,decimal edge,decimal near)=> d switch{"CostModel"=>"InvestigateCostDrag","SafetyBuffer"=>"InvestigateSafetyBuffer","MarketSpread"=>"MarketSpreadTooWide","MissingPricing" or "DataQuality"=>"IgnoreInvalid",_=>dir=="CompressingTowardBreakEven"?"CompressingTowardBreakEven":edge>=near&&dir=="Flat"?"NearBreakEvenButFlat":dir=="Flat"?"KeepWatching":"NoAction"};
    private static bool IsInvalid(string? r){var s=r??""; return new[]{"MissingYesAsk","MissingNoAsk","SuspiciousYesNoAskSum","TokenOutcomeMappingUnverified","ReviewOnly","DataQualityRejected","MissingPricing"}.Any(x=>s.Contains(x,StringComparison.OrdinalIgnoreCase));}
    private static string Fmt(decimal? v)=>v?.ToString("0.####")??"N/A";
    private void TryExport(EdgeCompressionSnapshot s,RuntimeHealthSnapshot h,FocusUniverseSnapshot? f,EdgeTransitionSnapshot? e,string root){try{var path=Path.Combine(root,"exports/edge-compression-latest.json");Directory.CreateDirectory(Path.GetDirectoryName(path)!);var payload=new{generatedAtUtc=DateTime.UtcNow,h.ProcessRunId,h.Uptime,enabled=s.Enabled,diagnosticsOnly=_options.EdgeCompression.DiagnosticsOnly,focusUniverseEnabled=f?.Enabled??false,edgeTransitionEnabled=e?.Enabled??false,h.PaperDiagnosticsLimitedEligible,h.OrderbookStableNow,h.ReducedUniverseOrderbookStableNow,items=s.Items,nearBreakEven=s.NearBreakEven,compressing=s.Compressing,expanding=s.Expanding,flat=s.Flat,rawPositive=s.RawPositive,afterCostPositive=s.AfterCostPositive,afterSafetyPositive=s.AfterSafetyPositive,blockedByMarketSpread=s.BlockedByMarketSpread,blockedByCost=s.BlockedByCost,blockedBySafety=s.BlockedBySafety,bestAfterSafetyEdge=s.BestAfterSafetyEdge,bestDistanceToBreakEven=s.BestDistanceToBreakEven,medianDistanceToBreakEven=s.MedianDistanceToBreakEven,p95AfterSafetyEdge=s.P95AfterSafetyEdge,dominantDragComponent=s.DominantDragComponent,consistent=s.Consistent,rankedItems=s.RankedItems.Select((x,i)=>new{rank=i+1,x.WatchlistId,x.TransitionId,x.Strategy,marketIdGroupKey=x.MarketIdOrGroupKey,x.Title,x.RawEdge,x.AfterCostEdge,x.AfterSafetyEdge,x.CostDrag,x.SafetyDrag,x.TotalDrag,x.DistanceToBreakEven,x.DistanceToAlertThreshold,x.RawWouldBePositive,x.AfterCostWouldBePositive,x.AfterSafetyWouldBePositive,x.BlockedByCostOnly,x.BlockedBySafetyOnly,x.BlockedByMarketSpread,x.DominantDragComponent,x.CompressionDelta,x.CompressionRatePerObservation,x.CompressionDirection,x.ObservationsInCompressionWindow,x.TransitionState,x.RecommendedAction})};var json=JsonSerializer.Serialize(payload,new JsonSerializerOptions{WriteIndented=true,PropertyNamingPolicy=JsonNamingPolicy.CamelCase});var tmp=path+".tmp";for(var i=0;i<3;i++){try{File.WriteAllText(tmp,json);File.Move(tmp,path,true);break;}catch(IOException) when(i<2){Thread.Sleep(50);}}}catch(Exception ex){Console.WriteLine($"[EDGE_COMPRESSION_EXPORT_WARNING] Error={ex.Message}");}}
}
